custom_css:
h1, h2, h3 {
    letter-spacing: -0.02em;
    line-height: 1.25;
    font-weight: 600;
}

p {
    letter-spacing: 0.01em;
    line-height: 1.7;
}

.text-muted,
.text-sm {
    letter-spacing: 0.05em;
    text-transform: uppercase;
}

img {
    filter: grayscale(10%) contrast(95%) brightness(95%);
    transition: filter 0.6s ease, transform 0.6s ease;
}

img:hover {
    filter: grayscale(0%) contrast(100%) brightness(100%);
}

img,
.card,
.btn {
    border-radius: 4px;
}

a,
button,
.btn,
.card {
    transition: all 0.4s cubic-bezier(0.25, 1, 0.5, 1);
}

.btn-primary:hover {
    opacity: 0.9;
    transform: translateY(-1px);
    box-shadow: 0 10px 20px color-mix(in srgb, var(--color-primary) 15%, transparent);
}

body {
    position: relative;
}

body::before {
    content: "";
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    opacity: 0.02;
    pointer-events: none;
    z-index: 9999;
    background: radial-gradient(circle, #fff 10%, transparent 11%), radial-gradient(circle, #fff 10%, transparent 11%);
    background-size: 3px 3px;
    background-position: 0 0, 1.5px 1.5px;
}

:is(body.light-mode, html.theme-light-init) .site-header {
    background-color: color-mix(in srgb, var(--color-primary) 8%, var(--color-surface) 92%);
    border-bottom-color: color-mix(in srgb, var(--color-primary) 16%, var(--color-border) 84%);
}

:is(body.light-mode, html.theme-light-init) .site-footer {
    background-color: color-mix(in srgb, var(--color-primary) 12%, var(--color-surface) 88%);
    border-top-color: color-mix(in srgb, var(--color-primary) 18%, var(--color-border) 82%);
}

::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: var(--color-bg-primary);
}

::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: var(--color-primary);
}

.post-read-more-btn {
    color: var(--color-primary) !important;
    background: transparent !important;
    border: 1px solid color-mix(in srgb, var(--color-primary) 20%, transparent) !important;
    text-transform: uppercase;
    font-weight: 500;
    letter-spacing: 0.05em;
}

.post-read-more-btn:hover {
    color: var(--btn-primary-color) !important;
    background: var(--color-primary) !important;
    border-color: var(--color-primary) !important;
    box-shadow: 0 4px 12px color-mix(in srgb, var(--color-primary) 15%, transparent);
}
